  const handleDelete = async () => {
    if (confirm(`Are you sure you want to delete group "${group.name}"?`)) {
      try {
        await toast.promise(api.delete(`/lab/panels/groups/${group.name}`), {
          loading: "Deleting group...",
          success: "Group deleted successfully",
